// Fonction récursive pour construire l'arborescence
const items = $input.all();

// Séparer dossiers et fichiers
const folders = [];
const files = [];

for (const item of items) {
  const data = item.json;
  if (data.mimeType === 'application/vnd.google-apps.folder') {
    folders.push({
      id: data.id,
      name: data.name,
      type: 'folder',
      parentId: data.parents ? data.parents[0] : null
    });
  } else {
    files.push({
      id: data.id,
      name: data.name,
      type: 'file',
      mimeType: data.mimeType,
      parentId: data.parents ? data.parents[0] : null
    });
  }
}

// Construire la structure nested
function buildTree(parentId = null) {
  const result = [];

  // Ajouter les sous-dossiers
  const subFolders = folders.filter(f => f.parentId === parentId);
  for (const folder of subFolders) {
    result.push({
      id: folder.id,
      name: folder.name,
      type: 'folder',
      children: buildTree(folder.id)
    });
  }

  // Ajouter les fichiers
  const folderFiles = files.filter(f => f.parentId === parentId);
  for (const file of folderFiles) {
    result.push({
      id: file.id,
      name: file.name,
      type: 'file',
      mimeType: file.mimeType
    });
  }

  return result;
}

// Trouver les éléments racine (sans parent ou parent = root)
const rootFolderIds = new Set(folders.map(f => f.id));
const rootItems = [...folders, ...files].filter(item => {
  return !item.parentId || !rootFolderIds.has(item.parentId);
});

// Construire depuis les racines
const tree = [];
for (const item of rootItems) {
  if (item.type === 'folder') {
    tree.push({
      id: item.id,
      name: item.name,
      type: 'folder',
      children: buildTree(item.id)
    });
  } else {
    tree.push({
      id: item.id,
      name: item.name,
      type: 'file',
      mimeType: item.mimeType
    });
  }
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    totalFolders: folders.length,
    totalFiles: files.length,
    structure: tree
  }
}];
